import {React , useState } from "react";
import './Design.css';
const[themes,setThemes]=useState([]);
useEffect(()=>{
    fetch("http://localhost:8080/admin/viewTheme")
    .then(res=>res.json())
    .then((result)=>{
      setThemes(result);
    }
  )
  })

function theme(){
    
<select id="themename">
{themes.map(theme => {
        return(
                <option value={theme.themeName} > {theme.themeName}</option> 
        )
    })}
</select>
}

export default theme;
